const items = $input.all();

function classify({ payload, driver, trip }) {
  const text = (payload.complaint_text || '').trim();
  if (text.length < 5) {
    return { 
      verdict: 'spam', 
      source: 'rules-spam', 
      reasoning: 'complaint text too short (<5 chars)', 
      risk_score: 0.95 
    };
  }

  // не знайшли drive-a
  if (!driver) {
    return { 
      verdict: 'fraud', 
      source: 'rules-unknown-driver', 
      reasoning: `driver_id ${payload.driver_id} not found`, 
      risk_score: 0.99 
    };
  }

  // не знайшли такий trip
  if (!trip) {
    return { 
      verdict: 'fraud', 
      source: 'rules-unknown-trip', 
      reasoning: `trip_id ${payload.trip_id} not found`, 
      risk_score: 0.95 
    };
  }

  // данний такий належить іншому драйверу 
  if (trip.driver_id !== payload.driver_id) {
    return {
      verdict: 'fraud',
      source: 'rules-trip-driver-mismatch',
      reasoning: `complainant ${payload.driver_id} but trip belongs to ${trip.driver_id}`,
      risk_score: 0.99,
    };
  }

  // 
  if (driver.account_status === 'banned') {
    return { 
      verdict: 'fraud', 
      source: 'rules-banned', 
      reasoning: 'driver account banned', 
      risk_score: 1.0 
    };
  }

  //
  if (driver.account_status === 'suspended') {
    return { 
      verdict: 'fraud', 
      source: 'rules-suspended', 
      reasoning: 'driver account suspended', 
      risk_score: 0.9 
    };
  }

  //
  if ((driver.history?.fraud_count_lifetime || 0) >= 5) {
    return {
      verdict: 'fraud',
      source: 'rules-many-fraud-requests',
      reasoning: `The driver has ${driver.history.fraud_count_lifetime} prior fraud confirmations`,
      risk_score: 0.85,
    };
  }

  //
  const flags = driver.flags || [];
  if (flags.includes('frequent_complaints') && (driver.history?.approval_rate ?? 1) < 0.4) {
    return {
      verdict: 'fraud',
      source: 'rules-low-approval-flagged',
      reasoning: `flagged "frequent_complaints" with approval_rate ${driver.history.approval_rate}`,
      risk_score: 0.8,
    };
  }
  const claimed = payload.claimed_amount;
  if (typeof claimed === 'number' && claimed > trip.fare_amount * 1.5) {
    return {
      verdict: 'fraud',
      source: 'rules-amount-toohigh',
      reasoning: `claimed ${claimed} vs fare ${trip.fare_amount}`,
      risk_score: 0.85,
    };
  }
  return {
    verdict: null,
    source: 'rules-passthrough',
    reasoning: 'no rule matched',
    risk_score: null,
  };
}

// Return decision per item, preserving caller's input for traceability
return items.map((it) => ({
  json: {
    ...it.json,
    rule_decision: classify(it.json),
  },
}));
